import { jsPDF } from "jspdf";
import mysql from "mysql2/promise";
import fs from "fs";
import path from "path";
import nodemailer from "nodemailer";
import { db } from "@/lib/db";

export default async function handler(req, res) {
  if (req.method !== "POST") {
    return res.status(405).json({ error: "Method Not Allowed" });
  }

  try {
    const { email } = req.body;
    if (!email) {
      return res.status(400).json({ error: "Email is required" });
    }



    // Fetch student data using email
    const [rows] = await db.query(
      "SELECT name, id_proof FROM students WHERE email = ?",
      [email]
    );

    if (rows.length === 0) {
      return res.status(404).json({ error: "Student not found" });
    }

    const { name, id_proof, phone_number } = rows[0];

    // Generate Offer Letter PDF
    const doc = new jsPDF();
    doc.text("Offer Letter", 20, 20);
    doc.text(`Dear ${name},`, 20, 40);
    doc.text(
      `We are pleased to offer you admission to the ${id_proof} id proof.`,
      20,
      50
    );
    doc.text(`Your phone number is: ${phone_number}`, 20, 60);
    doc.text("Best Regards,", 20, 80);
    doc.text("[Your Institution Name]", 20, 90);

    const uploadPath = path.join(process.cwd(), "public", "upload");
    if (!fs.existsSync(uploadPath)) {
      fs.mkdirSync(uploadPath, { recursive: true });
    }

    const pdfPath = path.join(
      uploadPath,
      `${name.replace(/\s+/g, "_")}_Offer_Letter.pdf`
    );
    doc.save(pdfPath);

    // Send Email with Offer Letter
    const transporter = nodemailer.createTransport({
      service: "Gmail",
      auth: {
        user: process.env.EMAIL_USER,
        pass: process.env.EMAIL_PASS,
      },
    });

    const mailOptions = {
      from: "bringmybuddy@gmail.com",
      to: email,
      subject: "Your Offer Letter",
      text: `Dear ${name},\n\nPlease find attached your offer letter.\n\nBest Regards,\n[Your Institution Name]`,
      attachments: [
        {
          filename: `${name.replace(/\s+/g, "_")}_Offer_Letter.pdf`,
          path: pdfPath,
        },
      ],
    };

    await transporter.sendMail(mailOptions);

    res
      .status(200)
      .json({ message: "Offer letter generated and sent successfully." });
  } catch (error) {
    console.error(error);
    res.status(500).json({ error: "Failed to generate and send offer letter" });
  }
}
